#include <vector>

namespace query_course_enrollment_stats {

struct Course {
  sqlgen::PrimaryKey<int> course_id;
  std::string title;
};

struct Enrollment {
  sqlgen::PrimaryKey<int> enrollment_id;
  sqlgen::ForeignKey<int, Course, "course_id"> course_id;
  std::optional<float> grade;
};

struct CourseStats {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

struct CourseStatsView {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 * 
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // 2. Create tables (using write with empty containers)
  sqlgen::write(conn, std::vector<Course>{});
  sqlgen::write(conn, std::vector<Enrollment>{});

  // 3. Build and execute the query
  auto query = sqlgen::select_from<Course, "c">("title"_t1)
             | sqlgen::left_join<Enrollment, "e">("course_id"_t1 == "course_id"_t2)
             | sqlgen::group_by("course_id"_t1, "title"_t1)
             | sqlgen::select("title"_t1, 
                              sqlgen::count("enrollment_id"_t2).as<"student_count">(),
                              sqlgen::avg("grade"_t2).as<"avg_grade">())
             | sqlgen::to<std::vector<CourseStatsView>>;

  auto result = query(conn);
  if (!result) {
    throw std::runtime_error("Query execution failed");
  }

  // 4. Convert results to CourseStats and return
  std::vector<CourseStats> stats;
  for (const auto& view : result.value()) {
    stats.push_back(CourseStats{
        .title = view.title,
        .student_count = view.student_count,
        .avg_grade = view.avg_grade
    });
  }

  return stats;
}

}  // namespace query_course_enrollment_stats
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Table Creation**: Uses `sqlgen::write()` with empty containers to create both Course and Enrollment tables

3. **Query Construction**: 
   - Uses `sqlgen::select_from()` with table alias "c" for Course
   - Applies `sqlgen::left_join()` with Enrollment table and join condition
   - Uses `sqlgen::group_by()` to group by course_id and title
   - Selects aggregated fields using `sqlgen::count()` and `sqlgen::avg()`
   - Uses `sqlgen::to()` to specify the return type as `std::vector<CourseStatsView>`

4. **Result Processing**: Converts the query results from `CourseStatsView` to `CourseStats` and returns the final vector

