    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        // Handle connection error - return empty vector
        return {};
    }
    auto conn = conn_result.value();

    // Build the base query
    auto query = read<std::vector<Book>>;

    // Conditionally add WHERE clauses based on non-null filters
    if (filters.title_keyword || filters.min_year || filters.genre || filters.max_price) {
        auto condition = where(
            (filters.title_keyword ? ("title"_c.like("%" + *filters.title_keyword + "%")) : true) &&
            (filters.min_year ? ("year"_c >= *filters.min_year) : true) &&
            (filters.genre ? ("genre"_c == *filters.genre) : true) &&
            (filters.max_price ? ("price"_c <= *filters.max_price) : true)
        );

        query = query | condition;
