namespace analyze_social_network {

struct User {
    sqlgen::PrimaryKey<int> user_id;
    std::string username;
    std::string email;
    sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
    std::string city;
};

struct Friendship {
    sqlgen::ForeignKey<int, User, "user_id"> user_id1;
    sqlgen::ForeignKey<int, User, "user_id"> user_id2;
    sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> friendship_date;
};

struct FriendConnection {
    std::string user1_name;
    std::string user2_name;
    int mutual_friend_count;
};

struct UserStats {
    int user_id;
    std::string username;
    int friend_count;
};

struct FriendRecommendation {
    std::string username;
    std::string recommended_username;
    std::string city;
};

std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    using namespace sqlgen::literals;

    // Create in-memory SQLite database connection
    auto conn = sqlgen::sqlite::connect(":memory:");

    // Create tables using sqlgen::CreateTable
    auto create_user_table = sqlgen::create_table<User>;
    auto create_friendship_table = sqlgen::create_table<Friendship>;

    // Insert data using sqlgen::insert
    auto insert_users = sqlgen::insert(users);
    auto insert_friendships = sqlgen::insert(friendships);

    // Execute queries using sqlgen's query building capabilities

    // 1. Find mutual friends using SELF-JOIN
    auto mutual_friends_query = 
        select_from<User, "u1">("username"_t1 | as<"user1_name">, "username"_t2 | as<"user2_name">)
        | inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t1)
        | inner_join<User, "f">("user_id2"_t1 == "user_id"_t2)
        | inner_join<Friendship, "f2">("user_id"_t2 == "user_id1"_t2)
        | inner_join<User, "u2">("user_id2"_t2 == "user_id"_t3 | as<"user2_id">)
        | where("user_id"_t1 < "user_id"_t3)
        | group_by("user_id"_t1, "user_id"_t3)
        | having(count() > 0);

    // 2. Find users with more than average friends using nested query
    auto avg_friends_subquery = 
        select_from<User, "u">(count("user_id2"_t1) | as<"friend_count">)
        | left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t1)
        | group_by("user_id"_t1);

    auto above_avg_users_query = 
        select_from<User, "u">(col<"user_id">, "username"_t1)
        | left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t1)
        | where(count("user_id2"_t1) > 
            (select_from<avg_friends_subquery>(avg("friend_count")) | to<double>))
        | order_by(count("user_id2"_t1) | desc());

    // 3. Find friend-of-friend relationships
    auto friend_of_friend_query = 
        select_from<User, "u1">("username"_t1 | as<"user1_name">, "username"_t2 | as<"user2_name">)
        | inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t1)
        | inner_join<User, "f">("user_id2"_t1 == "user_id"_t2)
        | inner_join<Friendship, "f2">("user_id"_t2 == "user_id1"_t2)
        | inner_join<User, "u2">("user_id2"_t2 == "user_id"_t3)
        | where("user_id"_t1 < "user_id"_t3)
        | group_by("user_id"_t1, "user_id"_t3)
        | having(count() == 1);

    // 4. Count friends per user and find most connected users
    auto friend_count_query = 
        select_from<User, "u">(col<"user_id">, "username"_t1, count("user_id2"_t1) | as<"friend_count">)
        | left_join<Friendship, "f">("user_id"_t1 == "user_id1"_t1)
        | group_by("user_id"_t1)
        | order_by("friend_count" | desc())
        | limit(10);

    // 5. Find users in same city not yet friends (recommendations)
    auto recommendation_query = 
        select_from<User, "u1">("username"_t1 | as<"username">, "city"_t1)
        | cross_join<User, "u2">()
        | where("user_id"_t1 < "user_id"_t2 && "city"_t1 == "city"_t2 &&
                !exists(select_from<Friendship, "f">() 
                    | where(("user_id1"_t3 == "user_id"_t1 && "user_id2"_t3 == "user_id"_t2) ||
                            ("user_id1"_t3 == "user_id"_t2 && "user_id2"_t3 == "user_id"_t1))))
        | select("username"_t1, "username"_t2 | as<"recommended_username">, "city"_t1);

    // Execute all queries and collect results
    auto mutual_results = mutual_friends_query(conn);
    auto friend_of_friend_results = friend_of_friend_query(conn);
    auto recommendation_results = recommendation_query(conn);

    // Convert results to appropriate data structures
    std::vector<FriendConnection> results;

    // Process mutual friends
    for (const auto& row : mutual_results) {
        FriendConnection fc;
        fc.user1_name = row.get<std::string>("user1_name");
        fc.user2_name = row.get<std::string>("user2_name");
        fc.mutual_friend_count = row.get<int>("friend_count");
        results.push_back(fc);
    }

    // Process friend-of-friend relationships
    for (const auto& row : friend_of_friend_results) {
        FriendConnection fc;
        fc.user1_name = row.get<std::string>("user1_name");
        fc.user2_name = row.get<std::string>("user2_name");
        fc.mutual_friend_count = 1; // Exactly one mutual friend
        results.push_back(fc);
    }

    // Process recommendations
    for (const auto& row : recommendation_results) {
        FriendRecommendation rec;
        rec.username = row.get<std::string>("username");
        rec.recommended_username = row.get<std::string>("recommended_username");
        rec.city = row.get<std::string>("city");

        // Add recommendation logic here if needed
    }

    return results;
}

}  // namespace analyze_social_network
