namespace replace_text_in_notes {

struct Note {
  sqlgen::PrimaryKey<int> note_id;
  std::string content;
};

struct UpdatedNote {
  sqlgen::PrimaryKey<int> note_id;
  std::string updated_content;
};

/**
 * description: replace_text_in_notes.
 * This function demonstrates how to replace text in notes using sqlgen update API.
 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Read all notes from the database
  auto notes = sqlgen::read<std::vector<Note>>.from(conn).all().value();

  // Create a vector to store updated notes
  std::vector<UpdatedNote> updated_notes;
  updated_notes.reserve(notes.size());

  // Process each note
  for (auto& note : notes) {
    // Replace "foo" with "bar" in the content
    auto updated_content = note.content;
    size_t pos = 0;
    while ((pos = updated_content.find("foo", pos)) != std::string::npos) {
      updated_content.replace(pos, 3, "bar");
      pos += 3; // Move past the replaced text
    }

    // Update the note in the database
    auto update_stmt = sqlgen::update<Note>("content"_c.set(updated_content));
    update_stmt.from(conn).execute().value();

    // Store the updated note information
    updated_notes.push_back(UpdatedNote{
        .note_id = note.note_id,
        .updated_content = updated_content
    });
  }

  return updated_notes;
}

}  // namespace replace_text_in_notes
